from pydantic import BaseModel, EmailStr, validator
from typing import Optional
from datetime import date

class UserRecord(BaseModel):
    id: int
    name: str
    email: Optional[EmailStr]
    age: Optional[int]
    signup_date: Optional[date]

    @validator("age")
    def age_must_be_valid(cls, v):
        if v is not None and not (0 <= v <= 120):
            raise ValueError(f"Age {v} out of valid range")
        return v

def validate_records(records: list[dict]) -> tuple[list[UserRecord], list[dict]]:
    valid, invalid = [], []
    for rec in records:
        try:
            valid.append(UserRecord(**rec))
        except Exception as e:
            invalid.append({"record": rec, "error": str(e)})
    return valid, invalid

import unicodedata

def normalize_unicode(text: str) -> str:
    if not isinstance(text, str):
        return text
    # NFC: canonical decomposition followed by canonical composition
    # This converts "café" (e + combining accent) → "café" (single character)
    return unicodedata.normalize("NFC", text)

df["name"] = df["name"].apply(normalize_unicode)

import hashlib

def redact_pii(record: dict) -> dict:
    safe = record.copy()
    if "email" in safe:
        safe["email"] = hashlib.sha256(str(safe["email"]).encode()).hexdigest()[:8] + "***"
    if "name" in safe:
        safe["name"] = safe["name"][0] + "***" if safe.get("name") else "***"
    return safe

