def assert_reasonable_row_loss(before: int, after: int, max_loss_pct: float = 0.20):
    loss_pct = (before - after) / before if before else 0
    if loss_pct > max_loss_pct:
        raise RuntimeError(
            f"Pipeline removed {loss_pct:.1%} of rows — exceeds threshold of {max_loss_pct:.1%}. "
            f"Aborting to prevent data loss."
        )
